import React, {
    forwardRef,
    useCallback,
    useEffect,
    useImperativeHandle,
    useRef,
    useState,
} from "react";
import type { IKitsInputTextarea } from "@lmb-it/kitsconcerto-types";
import KitsContainer from "../../helpers/FormContainer";
import { useSeparator } from "../../../factory";
import { applyKeyFilter } from "../InputText/keyFilter.native";
import {useFormFieldKeyboardNav} from "../../../hooks/useFormFieldKeyboardNav";
import {mergeRefs} from "../../../utils/mergeRefs";

// ✅ correct Gluestack components
import {
    Textarea,
    TextareaInput,
} from "@lmb-it/kitsconcertomobile";
import {useComponentDefaults, useResolvedStyle} from "@lmb-it/kitsconcerto/hooks";

type NativeTextareaRef = {
    focus(): void;
    blur(): void;
    clear(): void;
};

const KitsInputTextarea = forwardRef<
    NativeTextareaRef,
    IKitsInputTextarea
>((rawProps, ref) => {
    const {mergedProps: props, themeStyle, elementStyles} = useComponentDefaults('Textarea', rawProps, 'Input');
    const resolvedThemeStyle = useResolvedStyle(themeStyle);
    const resolvedRootStyle = useResolvedStyle(elementStyles?.root || {});
    const {
        id,
        label,
        value,
        defaultValue,
        onChange,
        keyFilter,
        errors,
        hideError,
        invalid,
        isFloatedLabel,
        disabled,
        helperText,
        inputSize,
        containerStyle,
        localProps,
        keyboardNavId,
        rows,
        autoResize,
        ...rest
    } = props;

    // Calculate height from rows: lineHeight × rows + vertical padding
    const LINE_HEIGHT = 20;
    const VERTICAL_PADDING = 16;
    const calculatedHeight = rows ? (LINE_HEIGHT * rows) + VERTICAL_PADDING : undefined;

    const {inputRef, navProps} = useFormFieldKeyboardNav(keyboardNavId ?? id);

    const isControlled = value !== undefined;

    const { cssProps, nativeProps } = useSeparator<any>({
        ...(rest as any),
        ...(localProps as any),
    });

    const fieldRef = useRef<any>(null);

    /** internal state for uncontrolled mode */
    const [internalValue, setInternalValue] = useState<string>(
        () => String(defaultValue ?? "")
    );

    /** sync when controlled */
    useEffect(() => {
        if (isControlled) {
            setInternalValue(String(value ?? ""));
        }
    }, [isControlled, value]);

    useImperativeHandle(ref, () => ({
        focus: () => fieldRef.current?.focus?.(),
        blur: () => fieldRef.current?.blur?.(),
        clear: () => {
            if (!isControlled) setInternalValue("");
            onChange?.({ target: { value: "" } } as any);
        },
    }));

    const handleChangeText = useCallback(
        (nextRaw: string) => {
            const prev = isControlled
                ? String(value ?? "")
                : internalValue;

            const filtered = keyFilter
                ? applyKeyFilter(prev, nextRaw, keyFilter as any)
                : nextRaw;

            if (!isControlled) {
                setInternalValue(filtered);
            }

            // Prime-like event
            onChange?.({ target: { value: filtered } } as any);
        },
        [keyFilter, onChange, isControlled, internalValue, value],
    );

    const displayValue = isControlled
        ? String(value ?? "")
        : internalValue;

    return (
        <KitsContainer
            id={id}
            helperText={helperText}
            isFloatedLabel={isFloatedLabel}
            errors={errors}
            invalid={invalid}
            label={label}
            hideError={hideError}
            disabled={disabled}
            inputSize={inputSize}
            containerStyle={containerStyle}
            elementStyles={elementStyles}
        >
            <Textarea
                size={inputSize ?? "md"}
                isDisabled={!!disabled}
                isInvalid={!!invalid}
                style={{
                    ...(resolvedRootStyle && Object.keys(resolvedRootStyle).length > 0 ? resolvedRootStyle : resolvedThemeStyle),
                    ...(cssProps as any),
                    ...(calculatedHeight ? {height: calculatedHeight, minHeight: calculatedHeight} : {}),
                }}
                {...nativeProps}
            >
                <TextareaInput
                    ref={mergeRefs(inputRef, fieldRef)}
                    value={displayValue}
                    onChangeText={handleChangeText}
                    editable={!disabled}
                    numberOfLines={rows ?? 4}
                    textAlignVertical="top"
                    style={calculatedHeight ? {height: calculatedHeight - VERTICAL_PADDING} : undefined}
                    {...navProps}
                />
            </Textarea>
        </KitsContainer>
    );
});

KitsInputTextarea.displayName = "KitsInputTextarea";
export default KitsInputTextarea;
